var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"결국 이 순간이 오고야 말았군.","JPN":"結局この時が来てしまったのか。","ENG":"Finally, it came down to this.","TWN":"這一刻終於來了呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"사람들이란 자기 안위를 챙기기에만 급급할 뿐, 그 밖의 일에는 관심 없지.","JPN":"人々は自分の安否だけを心配し、それ以外のことには興味がない。","ENG":"Most people are only interested in taking care of number one,","TWN":"人們汲汲營營，只為追求自己的安危，對其它的事情卻漠不關心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"하지만 그대는 그런 자들과 다르다는 걸 어렴풋이 알고 있었다.","JPN":"しかし、君はそんな者たちとは違う人間だと薄々気づいていた。","ENG":"but I have sensed, though vaguely, that you're not like them.","TWN":"但我隱約感覺到，你和那些人不一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"종신계약이라고 했던가?","JPN":"終身契約って言ったか？","ENG":"A lifetime contract, huh?","TWN":"是叫終身契約嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"우리가 이루고자 하는 목표에 비하면 조촐하기 짝이 없는 단어선택이지만......","JPN":"私たちが成し遂げようとしている目標に比べれば、卑小な単語だと思うが……","ENG":"That sounds so insignificant in comparison to our noble cause,","TWN":"和我們要達成的目標比起來，這個詞彙選擇也太樸素了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"이번 한 번은 너그러이 넘어가도록 하마.","JPN":"今回だけは大目に見てやろう。","ENG":"but I'll let it slide just this once.","TWN":"不過這次我就不計較了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"나와 한 배를 탄 이상, 수많은 악당들이 그대의 목숨을 노려올 것이다.","JPN":"私と同じ船に乗った以上、多くの悪党が君の命を狙うだろう。","ENG":"Now that you're in the same boat as I, myriad villains will come after you.","TWN":"既然你跟我上了同一條船，一定會有無數的壞人盯上你的性命。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"내 눈이 틀리지 않았다면, 그대는 고작 그런 위협에 굴할 생각이 없겠지?","JPN":"私の目に狂いがなければ、君はたかがその程度の脅威に屈するつもりはないのだろう。","ENG":"If I'm not wrong, you won't succumb to their threats, will you?","TWN":"如果我看人的眼光沒錯，你應該不會因為這點威脅就屈服吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"자, 나와 함께 악의 무리를 소탕하도록 하자고.","JPN":"さぁ、私とともに\\n悪の残党を掃討しようじゃないか。","ENG":"Alright, then let's subjugate the evil together.","TWN":"來吧，和我一起掃蕩邪惡吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"아, 이 계약은 우리 팀 고문에겐 비밀이다.","JPN":"あ、この契約はうちのチームの顧問には内緒にしてくれ。","ENG":"Ah, let's keep this contract secret from my team advisor.","TWN":"啊，對了，這份契約請對我們隊裡的顧問保密。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_NULL","text":{"KOREA":"그 여자는 인간의 탈을 쓴 도깨비가 분명하니 조심할 필요가 있어.","JPN":"あの女は人間の皮を被った鬼に違いないから、気をつけないと。","ENG":"She's a wolf in sheep's clothing. We must be careful around her.","TWN":"那女人可是戴著人皮面具的惡鬼，得小心她才行。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};